import{_ as n,o as a,c as e,ai as i}from"./chunks/framework.CaiDwmc7.js";const u=JSON.parse('{"title":"Redis 常用命令与过期策略","description":"","frontmatter":{},"headers":[],"relativePath":"redis/commands-expire.md","filePath":"redis/commands-expire.md"}'),p={name:"redis/commands-expire.md"};function l(r,s,t,o,d,c){return a(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="redis-常用命令与过期策略" tabindex="-1">Redis 常用命令与过期策略 <a class="header-anchor" href="#redis-常用命令与过期策略" aria-label="Permalink to “Redis 常用命令与过期策略”">​</a></h1><hr><h3 id="❓-面试官-redis-有哪些常用的基础命令-set、get、del、exists-这些命令的作用是什么" tabindex="-1">❓ 面试官：Redis 有哪些常用的基础命令？<code>SET</code>、<code>GET</code>、<code>DEL</code>、<code>EXISTS</code> 这些命令的作用是什么？ <a class="header-anchor" href="#❓-面试官-redis-有哪些常用的基础命令-set、get、del、exists-这些命令的作用是什么" aria-label="Permalink to “❓ 面试官：Redis 有哪些常用的基础命令？SET、GET、DEL、EXISTS 这些命令的作用是什么？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> Redis 的命令分为<strong>字符串操作</strong>、<strong>哈希操作</strong>、<strong>列表操作</strong>、<strong>集合操作</strong>、<strong>有序集合操作</strong>等几大类。基础命令是操作 Redis 的入门必备。</p><p><strong>📝 常用命令速查：</strong></p><p><strong>1. 字符串（String）命令</strong>：</p><div class="language-redis line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">redis</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>SET key value          # 设置键值对</span></span>
<span class="line"><span>GET key                # 获取值</span></span>
<span class="line"><span>DEL key                # 删除键</span></span>
<span class="line"><span>EXISTS key             # 判断键是否存在</span></span>
<span class="line"><span>EXPIRE key 60          # 设置过期时间（60秒）</span></span>
<span class="line"><span>TTL key                # 查看剩余过期时间</span></span>
<span class="line"><span>INCR key               # 自增1（常用于计数器）</span></span>
<span class="line"><span>DECR key               # 自减1</span></span>
<span class="line"><span>INCRBY key 10          # 自增10</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p><strong>2. 哈希（Hash）命令</strong>：</p><div class="language-redis line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">redis</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>HSET user:1 name &quot;张三&quot; age 25    # 设置哈希字段</span></span>
<span class="line"><span>HGET user:1 name                  # 获取字段值</span></span>
<span class="line"><span>HGETALL user:1                    # 获取所有字段和值</span></span>
<span class="line"><span>HDEL user:1 age                   # 删除字段</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>3. 列表（List）命令</strong>：</p><div class="language-redis line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">redis</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>LPUSH list &quot;a&quot; &quot;b&quot; &quot;c&quot;    # 从左边插入（栈）</span></span>
<span class="line"><span>RPUSH list &quot;d&quot;             # 从右边插入（队列）</span></span>
<span class="line"><span>LPOP list                  # 从左边弹出</span></span>
<span class="line"><span>RPOP list                  # 从右边弹出</span></span>
<span class="line"><span>LRANGE list 0 -1           # 获取所有元素</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>4. 集合（Set）命令</strong>：</p><div class="language-redis line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">redis</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>SADD tags &quot;Java&quot; &quot;Redis&quot;    # 添加元素</span></span>
<span class="line"><span>SMEMBERS tags               # 获取所有元素</span></span>
<span class="line"><span>SISMEMBER tags &quot;Java&quot;       # 判断元素是否存在</span></span>
<span class="line"><span>SREM tags &quot;Java&quot;           # 删除元素</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>🌟 实战应用场景：</strong> &quot;在项目中，我们常用 <code>INCR</code> 做接口访问计数、用 <code>EXPIRE</code> 做临时 Token 过期、用 <code>HSET</code> 存储用户信息（比多个 <code>SET</code> 更节省内存）。&quot;</p><hr><h3 id="❓-面试官-redis-的过期策略有哪些-ttl-命令返回-1-和-2-分别代表什么意思" tabindex="-1">❓ 面试官：Redis 的过期策略有哪些？<code>TTL</code> 命令返回 <code>-1</code> 和 <code>-2</code> 分别代表什么意思？ <a class="header-anchor" href="#❓-面试官-redis-的过期策略有哪些-ttl-命令返回-1-和-2-分别代表什么意思" aria-label="Permalink to “❓ 面试官：Redis 的过期策略有哪些？TTL 命令返回 -1 和 -2 分别代表什么意思？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> Redis 的过期策略有<strong>定时删除</strong>、<strong>惰性删除</strong>、<strong>定期删除</strong>三种。<code>TTL</code> 返回 <code>-1</code> 表示键<strong>永不过期</strong>，返回 <code>-2</code> 表示键<strong>不存在</strong>。</p><p><strong>📝 详细原理解析：</strong></p><ol><li><p><strong>定时删除</strong>：</p><ul><li>为每个过期键创建一个定时器，到期立即删除。</li><li><strong>缺点</strong>：如果过期键很多，会占用大量 CPU 资源。</li></ul></li><li><p><strong>惰性删除</strong>：</p><ul><li>只有当<strong>访问这个键时</strong>，才检查是否过期，过期就删除。</li><li><strong>缺点</strong>：如果过期键永远不被访问，会一直占用内存（内存泄漏）。</li></ul></li><li><p><strong>定期删除</strong>（Redis 实际采用）：</p><ul><li>Redis 每隔一段时间（默认 100ms），随机抽取一些设置了过期时间的键，检查并删除已过期的键。</li><li><strong>优点</strong>：平衡了 CPU 和内存，既不会占用太多 CPU，也不会让过期键堆积。</li></ul></li></ol><p><strong>🌟 TTL 返回值详解：</strong></p><div class="language-redis line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">redis</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>TTL key</span></span>
<span class="line"><span># 返回正数：剩余过期时间（秒）</span></span>
<span class="line"><span># 返回 -1：键存在但永不过期</span></span>
<span class="line"><span># 返回 -2：键不存在</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>🔥 内存淘汰策略（加分项）：</strong> &quot;如果 Redis 内存满了，且所有键都没有设置过期时间，Redis 会根据配置的淘汰策略（如 <code>allkeys-lru</code>、<code>volatile-lru</code>）自动删除一些键，为新数据腾出空间。&quot;</p>`,24)])])}const b=n(p,[["render",l]]);export{u as __pageData,b as default};
